/* еӨ§е…із»“з®—з”»йқў - еӨҡйӮ»еӣҪйЈҺж ј */
.final-modal {
    display: none;
    position: fixed;
    inset: 0;
    background: white;
    align-items: center;
    justify-content: center;
    z-index: 200;
    flex-direction: column;
}

.final-modal.show {
    display: flex;
    animation: finalIn 0.5s ease;
}

@keyframes finalIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

.final-content {
    text-align: center;
    padding: 40px 24px;
    width: 100%;
    max-width: 400px;
}

/* MaxеәҶзҘқеҪўиұЎ */
.final-max {
    width: 150px;
    height: 150px;
    background: white;
    border-radius: 50%;
    border: 4px solid #2196F3;
    margin: 0 auto 24px;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    animation: maxCelebrate 1s ease infinite alternate;
}

@keyframes maxCelebrate {
    0% { transform: scale(1) rotate(-5deg); }
    100% { transform: scale(1.05) rotate(5deg); }
}

.final-max-eyes {
    display: flex;
    gap: 8px;
}

.final-max-eye {
    width: 10px;
    height: 16px;
    background: #333;
    border-radius: 50%;
}

.final-max::before,
.final-max::after {
    content: 'вңЁ';
    position: absolute;
    font-size: 24px;
    animation: sparkle 1s ease infinite alternate;
}

.final-max::before {
    top: -10px;
    left: -10px;
}

.final-max::after {
    top: -10px;
    right: -10px;
    animation-delay: 0.5s;
}

@keyframes sparkle {
    0% { transform: scale(0.8); opacity: 0.7; }
    100% { transform: scale(1.2); opacity: 1; }
}

.final-title {
    font-size: 32px;
    font-weight: 800;
    color: #2196F3;
    margin-bottom: 12px;
}

.final-subtitle {
    font-size: 18px;
    color: #666;
    margin-bottom: 32px;
}

/* з»ҹи®ЎеҚЎзүҮ */
.final-stats {
    display: flex;
    gap: 16px;
    margin-bottom: 32px;
}

.final-stat-card {
    flex: 1;
    background: white;
    border-radius: 16px;
    padding: 20px 16px;
    border: 3px solid;
    text-align: center;
}

.final-stat-card.yellow {
    border-color: #FFC107;
}

.final-stat-card.blue {
    border-color: #2196F3;
}

.final-stat-label {
    font-size: 12px;
    color: #999;
    margin-bottom: 8px;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.final-stat-value {
    font-size: 28px;
    font-weight: 700;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 4px;
}

.final-stat-card.yellow .final-stat-value {
    color: #FFC107;
}

.final-stat-card.blue .final-stat-value {
    color: #2196F3;
}

.btn-final {
    background: linear-gradient(135deg, #2196F3, #1976D2);
    color: white;
    border: none;
    padding: 18px 48px;
    border-radius: 30px;
    font-size: 18px;
    font-weight: 700;
    cursor: pointer;
    box-shadow: 0 6px 20px rgba(33,150,243,0.4);
    transition: all 0.2s;
    width: 100%;
    max-width: 320px;
}

.btn-final:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 28px rgba(33,150,243,0.5);
}

